import { useState } from "react";
import "../styles/ProfilePage.css";

// ─── Mock data (replace with real API calls) ───────────────────────────────
const mockUser = {
  name: "Suyash Gokarankar",
  email: "suyash@example.com",
  phone: "+91 98765 43210",
  joinedDate: "January 2025",
  avatar: null, // set to a URL string to show an image
};

const mockHistory = [
  {
    id: 1,
    productName: "Sony WH-1000XM5 Headphones",
    searchedOn: "2025-06-10",
    bestPrice: "₹24,990",
    bestStore: "Amazon",
    image: "https://via.placeholder.com/60",
  },
  {
    id: 2,
    productName: "Apple iPhone 15",
    searchedOn: "2025-06-08",
    bestPrice: "₹79,900",
    bestStore: "Flipkart",
    image: "https://via.placeholder.com/60",
  },
  {
    id: 3,
    productName: "Samsung 65\" QLED TV",
    searchedOn: "2025-06-05",
    bestPrice: "₹1,12,000",
    bestStore: "Croma",
    image: "https://via.placeholder.com/60",
  },
  {
    id: 4,
    productName: "Logitech MX Master 3",
    searchedOn: "2025-06-01",
    bestPrice: "₹8,495",
    bestStore: "Amazon",
    image: "https://via.placeholder.com/60",
  },
];

// ─── Avatar initials helper ────────────────────────────────────────────────
function getInitials(name) {
  return name
    .split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);
}

// ─── Editable field row ────────────────────────────────────────────────────
function EditableField({ label, value, type = "text", editing, onChange }) {
  return (
    <div className="profileField">
      <span className="fieldLabel">{label}</span>
      {editing ? (
        <input
          className="fieldInput"
          type={type}
          value={value}
          onChange={(e) => onChange(e.target.value)}
        />
      ) : (
        <span className="fieldValue">{value}</span>
      )}
    </div>
  );
}

// ─── Main ProfilePage component ────────────────────────────────────────────
export default function ProfilePage() {
  const [user, setUser] = useState(mockUser);
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(mockUser);
  const [activeTab, setActiveTab] = useState("profile"); // "profile" | "history"
  const [saveMsg, setSaveMsg] = useState("");

  // Sidebar nav items (mirrors your existing sidebar style)

  function handleSave() {
    setUser(draft);
    setEditing(false);
    setSaveMsg("Changes saved!");
    setTimeout(() => setSaveMsg(""), 2500);

    // ── Django REST API call (uncomment when backend is ready) ──
    // fetch("/api/user/profile/", {
    //   method: "PATCH",
    //   headers: {
    //     "Content-Type": "application/json",
    //     Authorization: `Bearer ${localStorage.getItem("token")}`,
    //   },
    //   body: JSON.stringify({
    //     name: draft.name,
    //     email: draft.email,
    //     phone: draft.phone,
    //   }),
    // })
    //   .then((res) => res.json())
    //   .then((data) => console.log("Saved:", data))
    //   .catch((err) => console.error(err));
  }

  function handleCancel() {
    setDraft(user);
    setEditing(false);
  }

  return (
    <div className="profilePageContent">
        {/* Header */}
        <div className="profilePageHeader">
          <h1>My Profile</h1>
          <p>Manage your account and view your search history</p>
        </div>

        {/* Tab switcher */}
        <div className="profileTabs">
          <button
            className={`profileTab ${activeTab === "profile" ? "activeTab" : ""}`}
            onClick={() => setActiveTab("profile")}
          >
            Account Info
          </button>
          <button
            className={`profileTab ${activeTab === "history" ? "activeTab" : ""}`}
            onClick={() => setActiveTab("history")}
          >
            Recently Viewed
          </button>
        </div>

        {/* ── TAB: Profile ──────────────────────────────────── */}
        {activeTab === "profile" && (
          <div className="profileGrid">
            {/* Avatar card */}
            <div className="profileCard avatarCard">
              <div className="avatarCircle">
                {user.avatar ? (
                  <img src={user.avatar} alt="avatar" className="avatarImg" />
                ) : (
                  <span className="avatarInitials">{getInitials(user.name)}</span>
                )}
              </div>
              <h2 className="avatarName">{user.name}</h2>
              <p className="avatarSub">Member since {user.joinedDate}</p>
              <div className="statRow">
                <div className="statBox">
                  <span className="statNum">{mockHistory.length}</span>
                  <span className="statLabel">Searches</span>
                </div>
                <div className="statBox">
                  <span className="statNum">3</span>
                  <span className="statLabel">Platforms</span>
                </div>
              </div>
            </div>

            {/* Info card */}
            <div className="profileCard infoCard">
              <div className="infoCardHeader">
                <h3>Personal Details</h3>
                {!editing ? (
                  <button className="editBtn" onClick={() => setEditing(true)}>
                    ✏️ Edit
                  </button>
                ) : (
                  <div className="editActions">
                    <button className="saveBtn" onClick={handleSave}>
                      Save
                    </button>
                    <button className="cancelBtn" onClick={handleCancel}>
                      Cancel
                    </button>
                  </div>
                )}
              </div>

              {saveMsg && <div className="saveMsg">✅ {saveMsg}</div>}

              <div className="fieldsGrid">
                <EditableField
                  label="Full Name"
                  value={editing ? draft.name : user.name}
                  editing={editing}
                  onChange={(v) => setDraft({ ...draft, name: v })}
                />
                <EditableField
                  label="Email Address"
                  type="email"
                  value={editing ? draft.email : user.email}
                  editing={editing}
                  onChange={(v) => setDraft({ ...draft, email: v })}
                />
                <EditableField
                  label="Phone Number"
                  type="tel"
                  value={editing ? draft.phone : user.phone}
                  editing={editing}
                  onChange={(v) => setDraft({ ...draft, phone: v })}
                />
              </div>

              {/* Account actions */}
              <div className="accountActions">
                <h4>Account</h4>
                <button className="actionLink">🔒 Change Password</button>
                <button className="actionLink danger">🗑️ Delete Account</button>
              </div>
            </div>
          </div>
        )}

        {/* ── TAB: Recently Viewed ──────────────────────────── */}
        {activeTab === "history" && (
          <div className="historySection">
            {mockHistory.length === 0 ? (
              <div className="emptyState">
                <p>No recent searches yet. Start comparing prices!</p>
              </div>
            ) : (
              <div className="historyList">
                {mockHistory.map((item) => (
                  <div className="historyCard" key={item.id}>
                    <img
                      src={item.image}
                      alt={item.productName}
                      className="historyImg"
                    />
                    <div className="historyInfo">
                      <p className="historyProductName">{item.productName}</p>
                      <p className="historyMeta">
                        Searched on {item.searchedOn}
                      </p>
                    </div>
                    <div className="historyDeal">
                      <span className="historyPrice">{item.bestPrice}</span>
                      <span className="historyStore">on {item.bestStore}</span>
                    </div>
                    <button className="primaryBtn historyBtn">View Again</button>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
    </div>
  );
}
